<template><div><PageHeader eyebrow="ADMIN / NOTIFICATIONS" title="通知管理" description="向指定用户发送通知或发布全站公告"/><div class="two-column"><el-card shadow="never"><template #header>发送给指定用户</template><el-form :model="single" label-position="top"><el-form-item label="接收用户 ID"><el-input v-model="single.receiverId"/></el-form-item><el-form-item label="标题"><el-input v-model="single.title"/></el-form-item><el-form-item label="内容"><el-input v-model="single.content" type="textarea" :rows="4"/></el-form-item><el-form-item label="通知类型"><el-input v-model="single.noticeType"/></el-form-item><el-button type="primary" @click="sendSingle">发送通知</el-button></el-form></el-card><el-card shadow="never"><template #header>发布系统广播</template><el-form :model="broadcast" label-position="top"><el-form-item label="标题"><el-input v-model="broadcast.title"/></el-form-item><el-form-item label="内容"><el-input v-model="broadcast.content" type="textarea" :rows="4"/></el-form-item><el-form-item label="通知类型"><el-input v-model="broadcast.noticeType"/></el-form-item><el-button type="primary" @click="sendBroadcast">发布广播</el-button></el-form></el-card></div></div></template>
<script setup>import { reactive } from 'vue';import { ElMessage } from 'element-plus';import PageHeader from '../../components/PageHeader.vue';import { notificationApi } from '../../api/notification';const base={title:'',content:'',noticeType:'SYSTEM',targetType:null,targetId:null},single=reactive({receiverId:'',...base}),broadcast=reactive({...base});async function sendSingle(){await notificationApi.adminSend(single.receiverId,single);ElMessage.success('通知已发送')}async function sendBroadcast(){const result=await notificationApi.broadcast(broadcast);ElMessage.success(`广播完成：${result?.successCount??'已发送'} 个用户`)}</script>
